import "./home.css";

const Home = () => {
	return (
		<div class="home">
      <section>
        <h1>AJAY O S </h1>
        <div class="search-tab">
          <form action="https://www.google.com/search?" method="get">
            <input type="text" name="q" placeholder="Search..." className="search" required/>
          </form>
        </div>
    	</section>
    </div>
	);
};

export default Home;


